import React from 'react';
import { Outlet, Link } from '@tanstack/react-router';
import { ThemeProvider } from '../components/WorkflowAI/contexts/ThemeContext';

export function Root() {
  return (
    <ThemeProvider>
      <div className="flex flex-col h-screen bg-dark-bg text-dark-text-primary">
        <nav className="p-4 bg-dark-surface">
          <Link to="/" className="text-brand-primary hover:underline">
            Home
          </Link>
          <Link to="/workflow-ai" className="ml-4 text-brand-primary hover:underline">
            Workflow AI
          </Link>
        </nav>
        <Outlet />
      </div>
    </ThemeProvider>
  );
}

export default Root;